import { Diagram } from 'diagrams-js';
import { kubernetesPlugin } from '@diagrams-js/plugin-kubernetes';

const diagram = Diagram('My K8s Application');

// Register the plugin instance
await diagram.registerPlugins([kubernetesPlugin]);

// Import from Kubernetes YAML
const k8sYaml = `
apiVersion: apps/v1
kind: Deployment
metadata:
  name: web-deployment
  namespace: default
spec:
  replicas: 3
  selector:
    matchLabels:
      app: web
  template:
    spec:
      containers:
      - name: web
        image: nginx:latest
        ports:
        - containerPort: 80
---
apiVersion: v1
kind: Service
metadata:
  name: web-service
  namespace: default
spec:
  selector:
    app: web
  ports:
  - port: 80
    targetPort: 80
`;

await diagram.import(k8sYaml, 'kubernetes');

// Render the diagram
const svg = await diagram.render();

document.getElementById('diagram').innerHTML = svg;

